import unittest
class TestEasy(unittest.TestCase):
    def test_normal(self):
        self.assertEqual(average_list([1, 2, 3, 4, 5]), 3.0)
    def test_empty(self):
        self.assertEqual(average_list([]), 0)
    def test_float(self):
